head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.isSubCompany = false;

scwin.privAdmin = scwin.memJson.privAdmin;
scwin.txtCoClsCd = "";
scwin.isStart = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

};

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    ica_srchBudgetYm.setValue($c.date.getServerDateTime("yyyyMM"));
    $c.gus.cfTurnCreateFlag(true);
    scwin.f_FieldClear();
    $c.gus.cfDisableKey();
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ica_srchBudgetYm]);
    scwin.f_SetSrchDefault();
};

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function() {
    ica_srchBudgetYm.setValue($c.date.getServerDateTime("yyyyMM"));
    ica_srchBudgetYm.focus();
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    scwin.isStart = true;
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc,
        ed_coCd.getValue(), "",
        pWinCloseTF, null, null, null, null, null, null, null, null, null);
};

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
    // SET	
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);   // 코드
        ed_coNm.setValue(rtnList[5]);   // 회사명 
        scwin.txtCoClsCd = rtnList[1];  // 회사구분
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if(scwin.isStart == true) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) {    // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }

    scwin.isStart = false;
};

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    if (ds_master.getRowCount() > 0 && ds_master.getModifiedIndex().length > 0) {
        if (await $c.win.confirm(MSG_CM_CRM_005) == false)
            return;
    }

    let ret = await $c.gus.cfValidate([ica_srchBudgetYm]);
    if (!ret) {
        return false;
    }

    await $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 저장 :
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    let ret = await $c.gus.cfValidate([gr_master]);
    if (!ret) {
        return;
    }

    for(let i = 0; i < ds_master.getRowCount(); i++) {
        if(ds_master.getCellData(i, "budgetReduceRt") > 100) {
            await $c.win.alert("예산비용절감율리스트의 "+(i+1) + "번째 데이터에서 절감율(%)은(는) 100 이하로 입력하십시오.");
            gr_master.setFocusedCell(i, "budgetReduceRt", true);
            return
        }
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) {
        $c.sbm.execute(sbm_master);
    }
};

//-------------------------------------------------------------------------
// 예산통제계정 자동생성 팝업
//-------------------------------------------------------------------------
scwin.f_PupUpAutoCreation = function() {
    let param = ica_srchBudgetYm.getValue();

    let data = {
        param
    };

    const options = {
        id: "co_301_02_02p",
        type: "browserPopup",
        popupName:"예산비용절감율 자동생성",
        width: 720,
        height: 230
    };
    $c.win.openPopup("/ui/ac/co/budgetmgnt/co_301_02_02p.xml",options,data);
};

//------------------------------------------- 
// 그리드 데이터 엑셀로 다운 
//------------------------------------------- 
scwin.f_runExcel = async function() {
    let totCnt = ds_master.getRowCount();
    let sheetTitle = "예산비용절감률등록내역";

    if (totCnt != 0) {
        if (await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            const options = {
                fileName: sheetTitle + ".xlsx",
                sheetName: sheetTitle
            };
            await $c.data.downloadGridViewExcel(gr_master, options);
        }
    } else {
        await $c.win.alert(MSG_CM_WRN_002);
    }
};

//-------------------------------------------							
// 그리드 높이 늘리고 줄이기							
//-------------------------------------------		
scwin.f_grdHeiht = function (gridNm, size) {

    let strHeight = gridNm.style.height;
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
        gridNm.style.height = intHeight + "px";
    }
}

scwin.sbm_master_submitdone = async function (e) {
    if(e.responseJSON.resultDataSet[0].Code != -1){
        await $c.win.alert(MSG_CM_INF_001);
        ds_master.reform();
    }
};

scwin.sbm_search_submitdone = async function (e) {
    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(rowCnt);

    if( rowCnt == 0 ){
        if($c.gus.cfCheckCreateFlag() == true){
            $c.gus.cfTurnCreateFlag(false);
        } else {
            await $c.win.alert(MSG_CM_WRN_002);
        }
    } else {
        gr_master.focus();
    }
};

scwin.udc_dongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
    if (ed_coCd.getValue() != ""){
        scwin.f_PopUpCompanyInfo('T');
    }
    else{
        ed_coNm.setValue("");
    }
};

scwin.udc_dongbuGroupCompanyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.gr_master_onafteredit = function (rowIndex, columnIndex, value) {
    let colId = gr_master.getColumnID(columnIndex);
    if(colId == "budgetReduceRt"){
        if(value == "") {
            ds_master.setCellData(rowIndex, "budgetReduceRt", 0);
        }
    }
};
